async def main():
    client = AsyncIOMotorClient(MONGO_URL)
    db = client[DB_NAME]
    total = 0
    for level, lessons_data in FRENCH_CONTENT.items():
        course = await db.courses.find_one({"language": "french", "level": level})
        if not course:
            print(f"Course french-{level} not found!")
            continue
        lessons = await db.lessons.find({"course_id": str(course["_id"])}).sort("_id", 1).to_list(None)
        for i, data in enumerate(lessons_data):
            if i < len(lessons):
                await db.lessons.update_one(
                    {"_id": lessons[i]["_id"]},
                    {"$set": {"title": data["title"], "content": data["content"], "vocabulary": data["vocabulary"], "grammar_points": data["grammar_points"]}}
                )
                total += 1
        print(f"Updated french-{level}: {min(len(lessons_data), len(lessons))} lessons")
    print(f"\nTotal French lessons updated: {total}")
    client.close()

if __name__ == "__main__":
    asyncio.run(main())
